export function defaultLogFn(event: DaemonLogEvent): void {
  const line = JSON.stringify(event) + "\n";
  try {
    appendFileSync(LOG_FILE, line, "utf-8");
  } catch {
    // If the log file write fails, fall back to stderr so the failure is
    // at least visible in the daemon.ts spawn capture. Do not throw — the
    // daemon must not die on a log write failure.
  }
  // In detached mode (spawned by daemon.ts with stdio redirected to the log
  // file), process.stdout IS the log file fd — echoing would double-write.
  // daemon.ts sets ASL_DAEMON_DETACHED=1 on the detached child's env.
  // Foreground mode (running `bun src/services/self-learning-daemon/index.ts`
  // directly in a terminal) doesn't have that flag, so events echo to the
  // terminal for live debugging. Bun's process.stdout.isTTY is always
  // undefined regardless of context, so the env var is the reliable signal.
  if (process.env.ASL_DAEMON_DETACHED !== "1") {
    try {
      process.stdout.write(line);
    } catch {
      // stdout may be closed if something weird is happening with the
      // stdio redirect. Swallow.
    }
  }
}

